namespace App\Http\Middleware;

use Closure;
use Illuminate\Support\Facades\Cookie;
use Illuminate\Support\Facades\Session;

class UserPreferencesMiddleware
{
    public function handle($request, Closure $next)
    {
        // Check if the cookie exists and unserialize it
        if (Cookie::has('user_prefs')) {
            $preferences = unserialize(Cookie::get('user_prefs'));
            Session::put('user_preferences', $preferences);
        }

        $response = $next($request);

        // Get preferences from session, serialize them and store in a cookie
        $preferences = Session::get('user_preferences');
        if ($preferences) {
            Cookie::queue(Cookie::make('user_prefs', serialize($preferences), 60 * 24 * 30)); // expires in 30 days
        }

        return $response;
    }
}